/**
 * @param {number} n
 * @param {number[]} prices
 * @param {number[][]} roads
 * @return {number[]}
 */
function solve(n, prices, roads) {
    // Step 1: Calculate minimum cost to travel between any two shops with no apples (Empty Hand Travel Cost)
    // Since roads are bidirectional, we can use Floyd-Warshall or N Dijkstra runs.
    // Given N <= 1000, Floyd-Warshall O(N^3) is too slow (10^9). N Dijkstra runs O(N * (E log N)) is better.
    // Max E is ~2000. N * E log N is manageable.

    // Adjacency list for 'empty hand' travel (cost_i)
    const adjEmpty = Array(n).fill(0).map(() => []);
    for (const [u, v, cost, tax] of roads) {
        // Bidirectional
        adjEmpty[u].push({ to: v, weight: cost });
        adjEmpty[v].push({ to: u, weight: cost });
    }

    // distEmpty[i][j] = minimum cost to travel from i to j with empty hands
    const distEmpty = Array(n).fill(0).map(() => Array(n).fill(Infinity));

    for (let i = 0; i < n; i++) {
        distEmpty[i][i] = 0;
    }

    // Dijkstra for all pairs (running Dijkstra n times)
    const dijkstra = (startNode) => {
        const dist = Array(n).fill(Infinity);
        dist[startNode] = 0;
        // Min-heap: [distance, node]
        const pq = [[0, startNode]];

        while (pq.length > 0) {
            // Simple min-heap simulation using array sort/shift for simplicity in contest setting, 
            // though a proper binary heap would be faster. Given N=1000, let's rely on standard JS array behavior 
            // for a reasonable approximation or use a structure that behaves like a PQ.
            pq.sort((a, b) => a[0] - b[0]);
            const [d, u] = pq.shift();

            if (d > dist[u]) continue;

            for (const edge of adjEmpty[u]) {
                const v = edge.to;
                const weight = edge.weight;
                if (dist[u] + weight < dist[v]) {
                    dist[v] = dist[u] + weight;
                    pq.push([dist[v], v]);
                }
            }
        }
        return dist;
    };

    for (let i = 0; i < n; i++) {
        distEmpty[i] = dijkstra(i);
    }


    // Step 2: Calculate minimum cost to travel between any two shops with apples (Carrying Cost)
    // The cost is cost_i * tax_i.

    // Adjacency list for 'carrying' travel (cost_i * tax_i)
    const adjCarrying = Array(n).fill(0).map(() => []);
    for (const [u, v, cost, tax] of roads) {
        const carryingCost = cost * tax;
        // Bidirectional
        adjCarrying[u].push({ to: v, weight: carryingCost });
        adjCarrying[v].push({ to: u, weight: carryingCost });
    }

    // distCarrying[i][j] = minimum cost to travel from i to j while carrying apples
    const distCarrying = Array(n).fill(0).map(() => Array(n).fill(Infinity));

    for (let i = 0; i < n; i++) {
        distCarrying[i][i] = 0;
    }

    // Dijkstra for all pairs (running Dijkstra n times) using carrying costs
    const dijkstraCarrying = (startNode) => {
        const dist = Array(n).fill(Infinity);
        dist[startNode] = 0;
        const pq = [[0, startNode]];

        while (pq.length > 0) {
            pq.sort((a, b) => a[0] - b[0]);
            const [d, u] = pq.shift();

            if (d > dist[u]) continue;

            for (const edge of adjCarrying[u]) {
                const v = edge.to;
                const weight = edge.weight;
                if (dist[u] + weight < dist[v]) {
                    dist[v] = dist[u] + weight;
                    pq.push([dist[v], v]);
                }
            }
        }
        return dist;
    };

    for (let i = 0; i < n; i++) {
        distCarrying[i] = dijkstraCarrying(i);
    }


    // Step 3: Calculate the final minimum cost for each store i
    const ans = Array(n).fill(Infinity);

    for (let i = 0; i < n; i++) {
        // Option 1: Buy directly at shop i
        let minCost = prices[i];

        // Option 2: Travel empty-handed to j, buy at j, travel back to i carrying apples
        // Total Cost = Travel(i -> j, Empty) + Price[j] + Travel(j -> i, Carrying)

        for (let j = 0; j < n; j++) {
            if (i === j) continue;

            const costEmptyToJ = distEmpty[i][j];
            const costCarryingToI = distCarrying[j][i]; // j -> i while carrying

            if (costEmptyToJ !== Infinity && costCarryingToI !== Infinity) {
                // Total Cost = Empty Travel Cost (i->j) + Price at j + Carrying Travel Cost (j->i)
                const totalCost = costEmptyToJ + prices[j] + costCarryingToI;
                if (totalCost < minCost) {
                    minCost = totalCost;
                }
            }
        }
        ans[i] = minCost;
    }

    return ans;
}

