type Edge struct {
	to     int
	weight int64
}

// Priority Queue Item for Dijkstra's algorithm
type PQItem struct {
	distance int64
	node     int
}

// Simple Priority Queue implementation using a slice (Min-Heap behavior needed)
// For N=1000, a proper heap implementation would be ideal, but for contest simplicity,
// we simulate the behavior using standard library tools or careful manual sorting/searching if needed.
// Since Go lacks a built-in standard library priority queue suitable for this,
// we will use a slice and sort it/search for the minimum element in each iteration,
// which makes the complexity closer to O(V^2) per Dijkstra run, but often passes for sparse graphs
// or smaller constraints, though theoretically slower than O(E log V). Given E <= 2000, N*V^2 is too slow if V=1000.
// Let's stick to the structure mimicking the reference solution's complexity approach (N Dijkstra runs)
// and use a slightly optimized approach for PQ simulation if possible, otherwise, rely on the structure.

// A proper implementation would use container/heap. For this constrained environment,
// we'll implement a basic structure that resembles Dijkstra's process.

func dijkstra(n int, adj map[int][]Edge, startNode int) []int64 {
	dist := make([]int64, n)
	for i := range dist {
		dist[i] = math.MaxInt64
	}
	dist[startNode] = 0

	// PQ stores [distance, node]. We use a slice and manually find the minimum.
	pq := []PQItem{{distance: 0, node: startNode}}

	for len(pq) > 0 {
		// Find element with minimum distance (Simulating Pop from Min-Heap)
		minIndex := 0
		for i := 1; i < len(pq); i++ {
			if pq[i].distance < pq[minIndex].distance {
				minIndex = i
			}
		}

		item := pq[minIndex]
		pq[minIndex] = pq[len(pq)-1]
		pq = pq[:len(pq)-1]

		d := item.distance
		u := item.node

		if d > dist[u] {
			continue
		}

		for _, edge := range adj[u] {
			v := edge.to
			weight := edge.weight
			if dist[u] != math.MaxInt64 && dist[u]+weight < dist[v] {
				dist[v] = dist[u] + weight
				pq = append(pq, PQItem{distance: dist[v], node: v})
			}
		}
	}
	return dist
}

