		if _, ok := adjEmpty[u]; !ok {
			adjEmpty[u] = []Edge{}
		}
		adjEmpty[u] = append(adjEmpty[u], Edge{to: v, weight: cost})

		if _, ok := adjEmpty[v]; !ok {
			adjEmpty[v] = []Edge{}
		}
		adjEmpty[v] = append(adjEmpty[v], Edge{to: u, weight: cost})
	}

	// distEmpty[i][j] = minimum cost to travel from i to j with empty hands
	distEmpty := make([][]int64, N)
	for i := range distEmpty {
		distEmpty[i] = make([]int64, N)
	}

	for i := 0; i < N; i++ {
		distEmpty[i] = dijkstra(N, adjEmpty, i)
	}

	// --- Step 2: Carrying Cost Travel (Cost = cost_i * tax_i) ---
	adjCarrying := make(map[int][]Edge)
	for _, road := range roads {
		u, v := int(road[0]), int(road[1])
		cost := road[2]
		tax := road[3]
		carryingCost := cost * tax

		if _, ok := adjCarrying[u]; !ok {
			adjCarrying[u] = []Edge{}
		}
		adjCarrying[u] = append(adjCarrying[u], Edge{to: v, weight: carryingCost})

		if _, ok := adjCarrying[v]; !ok {
			adjCarrying[v] = []Edge{}
		}
		adjCarrying[v] = append(adjCarrying[v], Edge{to: u, weight: carryingCost})
	}

	// distCarrying[i][j] = minimum cost to travel from i to j while carrying apples
	distCarrying := make([][]int64, N)
	for i := range distCarrying {
		distCarrying[i] = make([]int64, N)
	}

	for i := 0; i < N; i++ {
		distCarrying[i] = dijkstra(N, adjCarrying, i)
	}

	// --- Step 3: Calculate the final minimum cost for each store i ---
	ans := make([]int64, N)

	for i := 0; i < N; i++ {
		// Option 1: Buy directly at shop i
		minCost := prices[i]

		// Option 2: Travel empty-handed to j, buy at j, travel back to i carrying apples
		// Total Cost = Travel(i -> j, Empty) + Price[j] + Travel(j -> i, Carrying)

		for j := 0; j < N; j++ {
			if i == j {
				continue
			}

			costEmptyToJ := distEmpty[i][j]
			// We need j -> i while carrying
			costCarryingToI := distCarrying[j][i] 

			if costEmptyToJ != math.MaxInt64 && costCarryingToI != math.MaxInt64 {
				// Total Cost = Empty Travel Cost (i->j) + Price at j + Carrying Travel Cost (j->i)
				totalCost := costEmptyToJ + prices[j] + costCarryingToI
				if totalCost < minCost {
					minCost = totalCost
				}
			}
		}
		ans[i] = minCost
	}

	return ans
