func dijkstra(adj [][]Edge, n int, startNode int) []int64 {
	dist := make([]int64, n)
	for i := range dist {
		dist[i] = math.MaxInt64
	}
	dist[startNode] = 0

	pq := make(PriorityQueue, 0)
	heap.Push(&pq, &Item{value: 0, node: startNode})

	for pq.Len() > 0 {
		item := heap.Pop(&pq).(*Item)
		d := item.value
		u := item.node

		if d > dist[u] {
