package main

import (
	"container/heap"
	"math"
)

// Item represents a node in the priority queue for Dijkstra's algorithm
type Item struct {
	distance int64
	node     int
}

// PriorityQueue implements heap.Interface and holds Items.
type PriorityQueue []*Item

func (pq PriorityQueue) Len() int { return len(pq) }

func (pq PriorityQueue) Less(i, j int) bool {
	// We want a min-heap based on distance
	return pq[i].distance < pq[j].distance
}

func (pq PriorityQueue) Swap(i, j int) {
	pq[i], pq[j] = pq[j], pq[i]
}

func (pq *PriorityQueue) Push(x interface{}) {
	item := x.(*Item)
	*pq = append(*pq, item)
}

func (pq *PriorityQueue) Pop() interface{} {
	old := *pq
	n := len(old)
	item := old[n-1]
	*pq = old[0 : n-1]
	return item
}

// Edge represents a connection between two shops
type Edge struct {
	to     int
	weight int64
}

func solve(n int64, prices []int64, roads [][]int64) []int64 {
	N := int(n)

	// --- Step 1: Calculate minimum cost to travel between any two shops with no apples (Empty Hand Travel Cost) ---

